/// @file neon_fp32_2x16.cpp
/// Auto-generated packed 2x16 FP32 NEON micro-kernel.
/// Generated by: tools/gen_neon_gemm.py
///   Mr=2, Nr=16, K_unroll=4
///   Register budget: 8 acc + 4 B + 1 A = 13 regs
///   1-pass (fits in 32 regs)

#include "dnnopt/gemm/gemm_config.h"
#include "dnnopt/gemm/gemm_ukernel_registry.h"

#include <algorithm>
#include <cstring>

